// v2 RAG: build Gemini text-embedding-004 request body for the buyer's inquiry.
// We embed the combined text the buyer would actually say (inquiry_text + their structured intent
// signals) so the resulting vector matches against property embeddings semantically, not just on
// city/budget arithmetic. The embedding is then fed into the match_properties_for_inquiry RPC.
const lead = $('Supabase: Insert Lead').first().json;
const webhookBody = $('Webhook: New Lead').first().json.body || {};

const inquiryText = lead.inquiry_text || webhookBody.inquiry_text || '';
const budget      = lead.budget_lakhs || webhookBody.budget_lakhs || null;
const city        = lead.preferred_city || webhookBody.preferred_city || null;
const config      = lead.preferred_config || webhookBody.preferred_config || null;
const timeline    = lead.purchase_timeline || webhookBody.purchase_timeline || null;

const combinedText = [
  inquiryText,
  config   ? `Configuration: ${config}.` : '',
  city     ? `City: ${city}.` : '',
  budget   ? `Budget around ${budget} lakhs.` : '',
  timeline ? `Timeline: ${timeline}.` : ''
].filter(Boolean).join(' ');

const embeddingBody = JSON.stringify({
  model:    'models/gemini-embedding-001',
  content:  { parts: [{ text: combinedText }] },
  taskType: 'RETRIEVAL_QUERY',
  outputDimensionality: 768
});

return [{ json: { combinedText, embeddingBody, preferredCity: city, leadBudget: budget } }];

// v3 RAG (audit item 3.3 replaced with proper semantic retrieval): consumes the
// top-K properties from the match_properties_for_inquiry RPC (Gemini-embedded
// inquiry → pgvector cosine match). The naive city + budget JS filter is now a
// fallback only — only fires if the RPC returned 0 rows (embedding service down,
// or property_embeddings table not yet populated).
const leadRow      = $('Supabase: Insert Lead').first().json;
// Tolerant feedback read: if Get Historical Feedback errored or wasn't executed,
// fall back to an empty feedback object instead of crashing the workflow.
let feedbackRaw;
try { feedbackRaw = $('Supabase: Get Historical Feedback').first().json; }
catch (e) { feedbackRaw = null; }
// v3.3 RAG read — defensive against both n8n HTTP behaviors:
//   a) keeps the JSON array as one item's .json (current behavior in your n8n version)
//   b) splits array elements into separate items
// Either way we end up with ragRaw = [{prop1}, {prop2}, ..., {prop6}]
const _ragItems = $('HTTP: RAG Match Properties').all();
let ragRaw;
if (_ragItems.length === 1 && Array.isArray(_ragItems[0].json)) {
  ragRaw = _ragItems[0].json;
} else {
  ragRaw = _ragItems.map(i => i.json).filter(j => j && typeof j === 'object' && j.id);
}
const embedCtx     = $('Code: Build Embedding Body').first().json;
const t0 = Date.now();
const traceId = (typeof crypto !== 'undefined' && crypto.randomUUID) ? crypto.randomUUID() : ('xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => { const r = Math.random()*16|0; const v = c==='x' ? r : (r&0x3|0x8); return v.toString(16); }));

const preferredCity = embedCtx?.preferredCity || null;
const leadBudget    = Number(embedCtx?.leadBudget || 0);

// RAG path (preferred): use the RPC results directly.
let properties = [];
let retrievalMode = 'rag';
let retrievalDiagnostics = {};

if (Array.isArray(ragRaw) && ragRaw.length > 0) {
  properties = ragRaw.map(r => ({
    id: r.id,
    project_name: r.project_name,
    developer: r.developer,
    city: r.city,
    locality: r.locality,
    config: r.config,
    price_min_lakhs: r.price_min_lakhs,
    price_max_lakhs: r.price_max_lakhs,
    possession_date: r.possession_date,
    highlights: r.highlights || [],
    amenities: r.amenities || [],
    // RAG-only fields the scoring prompt can use:
    rag_similarity: r.similarity,
    rag_city_match: r.city_match,
    rag_budget_overlap: r.budget_overlap
  }));
  retrievalDiagnostics = {
    retrieved_count: properties.length,
    top_similarity: properties[0]?.rag_similarity || null,
    city_matches: properties.filter(p => p.rag_city_match).length,
    budget_overlaps: properties.filter(p => p.rag_budget_overlap).length
  };
} else {
  // Fallback (should rarely fire): RPC returned nothing → embedding service likely down
  // OR property_embeddings is empty. Surface this in the diagnostics so it's visible.
  retrievalMode = 'fallback_empty';
  retrievalDiagnostics = { retrieved_count: 0, fallback_reason: 'rag_returned_empty' };
}

const feedback = {
  by_source: feedbackRaw?.by_source || [],
  top_objections_by_project: feedbackRaw?.top_objections_by_project || []
};

// v3.1 (production hardening): Gemini Score Lead body with FORCED responseSchema.
// responseSchema is the API-level guarantee that the output matches the structure.
// Without it, responseMimeType only nudges Gemini to emit JSON-shaped text; with it,
// Gemini's decoder enforces the shape. ~80% of our parse failures came from missing fields
// or non-integer scores. This eliminates that class of bugs.
const systemText = "You are the Lead Scoring Agent for an Indian residential real estate sales platform. Ground every claim in the provided LEAD DATA and AVAILABLE PROPERTIES (retrieved via semantic embedding similarity — pre-filtered to be relevant). Do not invent facts. If fewer than 2 intent fields are present, set confidence below 50. Budgets are in INR lakhs. recommended_action MUST be one of: 'Schedule site visit', 'Send brochure', 'Long-term nurture', 'Disqualify', 'Escalate to manager'.";
const userText = 'LEAD DATA:\n' + JSON.stringify(leadRow, null, 2) + '\n\nAVAILABLE PROPERTIES (RAG top-' + properties.length + '):\n' + JSON.stringify(properties, null, 2) + '\n\nHISTORICAL FEEDBACK:\n' + JSON.stringify(feedback, null, 2) + '\n\nScore this lead.';

// Gemini-flavored JSON schema (uses uppercase type names, supports STRING enum)
const responseSchema = {
  type: 'OBJECT',
  properties: {
    fit_score:       { type: 'INTEGER', description: '0-100, how well the lead matches the available properties' },
    urgency_score:   { type: 'INTEGER', description: '0-100, how soon the buyer is likely to transact' },
    overall_score:   { type: 'INTEGER', description: '0-100, weighted blend of fit + urgency' },
    confidence:      { type: 'INTEGER', description: '0-100, how confident you are in the scoring' },
    fit_reasons:     { type: 'ARRAY', items: { type: 'STRING' } },
    urgency_reasons: { type: 'ARRAY', items: { type: 'STRING' } },
    recommended_action: {
      type: 'STRING',
      enum: ['Schedule site visit', 'Send brochure', 'Long-term nurture', 'Disqualify', 'Escalate to manager']
    },
    matched_property_id:   { type: 'STRING', description: 'UUID of the best matching property from RAG results, or empty string' },
    matched_property_name: { type: 'STRING', description: 'Project name of the best matching property, or empty string' }
  },
  required: ['fit_score','urgency_score','overall_score','confidence','fit_reasons','recommended_action']
};

const geminiScoreBody = JSON.stringify({
  systemInstruction: { parts: [{ text: systemText }] },
  contents: [{ role: 'user', parts: [{ text: userText }] }],
  generationConfig: {
    temperature: 0.2,
    responseMimeType: 'application/json',
    responseSchema
  }
});

return [{
  json: {
    lead: leadRow,
    properties,
    feedback,
    traceId,
    promptStartedAt: t0,
    promptVersion: 'lead_scoring.v3.3_rag_defensive',
    retrievalMode,
    retrievalDiagnostics,
    geminiScoreBody,
    filterDiagnostics: {
      preferred_city: preferredCity,
      lead_budget_lakhs: leadBudget || null,
      retrieved_count: properties.length,
      retrieval_mode: retrievalMode
    }
  }
}];

// v3.1 production hardening: Gemini Score with retry + model fallback chain.
// Pattern: Flash twice (transient errors) → Flash-Lite (cheaper retry) → Pro (slow but most reliable).
// Every attempt uses the same responseSchema-enforced body so Gemini's decoder validates structure.
// Returns { ok, score, modelUsed, attemptsUsed, latencyMs, lastError } so observability is preserved.
const body = $('Code: Build Context').first().json.geminiScoreBody;
const apiKey = $env.GEMINI_API_KEY;
const startedAt = Date.now();

const chain = [
  { model: 'gemini-2.5-flash',      label: 'flash-1' },
  { model: 'gemini-2.5-flash',      label: 'flash-2' },
  { model: 'gemini-2.5-flash-lite', label: 'flash-lite' },
  { model: 'gemini-2.5-pro',        label: 'pro-fallback' }
];

const required = ['fit_score','urgency_score','overall_score','confidence','fit_reasons','recommended_action'];

async function tryOnce(attempt) {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/${attempt.model}:generateContent?key=${apiKey}`;
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url,
    headers: { 'Content-Type': 'application/json' },
    body,
    json: true,
    returnFullResponse: false,
    timeout: 25000
  });
  const text = resp?.candidates?.[0]?.content?.parts?.[0]?.text;
  if (!text) throw new Error('empty_response_text');
  const parsed = typeof text === 'string' ? JSON.parse(text) : text;
  for (const f of required) {
    if (parsed[f] === undefined || parsed[f] === null || parsed[f] === '') {
      throw new Error('missing_required_field:' + f);
    }
  }
  return parsed;
}

let lastError = null;
let result = null;
let usedModel = null;
let attemptCount = 0;
const attemptLog = [];

for (const attempt of chain) {
  attemptCount++;
  const t0 = Date.now();
  try {
    result = await tryOnce.call(this, attempt);
    usedModel = attempt.model;
    attemptLog.push({ label: attempt.label, model: attempt.model, ms: Date.now() - t0, status: 'ok' });
    break;
  } catch (e) {
    lastError = `${attempt.label}: ${e.message}`;
    attemptLog.push({ label: attempt.label, model: attempt.model, ms: Date.now() - t0, status: 'fail', error: e.message });
    // Small backoff before next attempt (skip on last)
    if (attemptCount < chain.length) {
      await new Promise(r => setTimeout(r, 400 * attemptCount));
    }
  }
}

const latencyMs = Date.now() - startedAt;

if (!result) {
  // All attempts failed — return a structured low-confidence fallback so the workflow still completes,
  // and the lead correctly routes to manager escalation instead of silently disappearing.
  return [{
    json: {
      ok: false,
      score: {
        fit_score: 0,
        urgency_score: 0,
        overall_score: 0,
        confidence: 0,
        fit_reasons: ['All Gemini attempts failed. Routing to manager. Last error: ' + lastError],
        urgency_reasons: [],
        recommended_action: 'Escalate to manager',
        matched_property_id: null,
        matched_property_name: null
      },
      modelUsed: null,
      attemptsUsed: attemptCount,
      attemptLog,
      latencyMs,
      lastError
    }
  }];
}

return [{
  json: {
    ok: true,
    score: result,
    modelUsed: usedModel,
    attemptsUsed: attemptCount,
    attemptLog,
    latencyMs,
    lastError: null
  }
}];

// v3.1 production hardening: reads from the new Code: Score Lead (Retry+Fallback) output.
// That node ALWAYS returns a structured payload — even on total Gemini failure it returns
// a confidence-0 routed-to-manager fallback. So we just clamp + validate + prep for Supabase.
const leadRow = $('Supabase: Insert Lead').first().json;
const scoreNode = $('Code: Score Lead (Retry+Fallback)').first().json;
const score = scoreNode.score;

const clamp = (v) => Math.max(0, Math.min(100, parseInt(v, 10) || 0));
const allowedActions = ['Schedule site visit','Send brochure','Long-term nurture','Disqualify','Escalate to manager'];
const toUuidOrNull = (v) => (typeof v === 'string' && /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(v)) ? v : null;

const out = {
  lead_id: leadRow.id,
  lead_name: leadRow.name,
  lead_phone: leadRow.phone,
  lead_budget_lakhs: leadRow.budget_lakhs,
  fit_score: clamp(score.fit_score),
  urgency_score: clamp(score.urgency_score),
  overall_score: clamp(score.overall_score || Math.round(clamp(score.fit_score) * 0.55 + clamp(score.urgency_score) * 0.45)),
  confidence: clamp(score.confidence),
  fit_reasons: Array.isArray(score.fit_reasons) ? score.fit_reasons : [],
  urgency_reasons: Array.isArray(score.urgency_reasons) ? score.urgency_reasons : [],
  recommended_action: allowedActions.includes(score.recommended_action) ? score.recommended_action : 'Escalate to manager',
  matched_property_id: toUuidOrNull(score.matched_property_id),
  matched_property_name: (typeof score.matched_property_name === 'string' && score.matched_property_name.length > 0) ? score.matched_property_name : null,
  raw_response: score,
  prompt_version: $('Code: Build Context').first().json.promptVersion || 'unknown',
  // v3.1 observability — these surface in the LEAD_SCORED event payload + dashboard activity feed
  scoring_ok: scoreNode.ok,
  model_used: scoreNode.modelUsed,
  attempts_used: scoreNode.attemptsUsed,
  scoring_latency_ms: scoreNode.latencyMs,
  attempt_log: scoreNode.attemptLog,
  last_error: scoreNode.lastError
};

return [{ json: out }];

