parameters.jsCode:
// v1.1 spec rev. 3 — Intent Completeness verdict.
// Implements the three-way branch precondition: classifies the lead into
// `sufficient` or `insufficient` based on hard gates + score signals + field count.
//
// Hard gate (locked decision 1): purpose missing => insufficient regardless.
// Score gates: confidence < 50 OR fit_score < 40 => insufficient.
// Count gate: critical_missing_count > 2 => insufficient.
//
// Field ask-priority order (locked): purpose -> budget -> timeline -> config -> locality -> loan
const score = $('Code: Parse and Validate Score').first().json;
const lead = $('Supabase: Insert Lead').first().json;
const ctx = $('Code: Build Context').first().json;

const FIT_FLOOR = 40;
const CONFIDENCE_FLOOR = 50;
const MAX_CRITICAL_MISSING = 2;

// Priority-ordered list of intent fields the buyer should reveal.
const PRIORITY_FIELDS = [
  { name: 'purpose',            value: lead.purpose },
  { name: 'budget_lakhs',       value: lead.budget_lakhs },
  { name: 'purchase_timeline',  value: lead.purchase_timeline },
  { name: 'preferred_config',   value: lead.preferred_config },
  { name: 'preferred_locality', value: lead.preferred_locality || lead.preferred_city },
  { name: 'loan_status',        value: lead.loan_status },
];

const missing_fields = PRIORITY_FIELDS
  .filter(f => f.value === null || f.value === undefined || f.value === '' || f.value === 'not_sure')
  .map(f => f.name);

const purpose_missing = missing_fields.includes('purpose');
const critical_missing_count = missing_fields.filter(n => n !== 'purpose').length;

// Step A.1: No-inventory guard. If RAG returned 0 properties, we cannot
// fabricate a match. Mark and force insufficient (still ask for purpose if missing).
const no_inventory_match = (ctx.properties && ctx.properties.length === 0);

let data_sufficiency;
if (purpose_missing) {
  data_sufficiency = 'insufficient';
} else if (no_inventory_match) {
  data_sufficiency = 'insufficient';
} else if (score.confidence < CONFIDENCE_FLOOR || score.fit_score < FIT_FLOOR) {
  data_sufficiency = 'insufficient';
} else if (critical_missing_count > MAX_CRITICAL_MISSING) {
  data_sufficiency = 'insufficient';
} else {
  data_sufficiency = 'sufficient';
}


// Spec Step A.1 fix: when Disqualify/Escalate is driven by RAG miss + missing
// intent (not by a real bad-fit signal), reroute to gap-fill so we capture
// the buyer's purpose for future inventory.
let final_action = score.recommended_action;
const reroute_to_gap_fill = (
  (no_inventory_match || purpose_missing || critical_missing_count > 0) &&
  (final_action === 'Disqualify' || final_action === 'Escalate to manager')
);
if (reroute_to_gap_fill) {
  final_action = 'Long-term nurture';
}

// Pass everything through plus the new fields. Downstream Insert Lead Score
// reads from this node now.
return [{
  json: {
    ...score,
    recommended_action: final_action,
    data_sufficiency,
    missing_fields,
    critical_missing_count,
    no_inventory_match,
    // Force the matched_property_id to null if we have no inventory — never fabricate
    matched_property_id: no_inventory_match ? null : score.matched_property_id,
    matched_property_name: no_inventory_match ? null : score.matched_property_name
  }
}];

